#!/usr/bin/env bash
# Build the moonshine PUPPET image the sovereign, Docker-free way:
#   1. cross-compile moonshine → static linux-musl on the HOST via zig
#      (zig compiles tree-sitter's C — no musl-cross toolchain, no in-container build),
#   2. layer the RUN-free Containerfile.puppet-musl into Alpine with `swerve`
#      (content-addressed file layering, no Linux daemon — the broadcaster-sliver path).
#
# Usage:  open-source/gnosis/moonshine/build-puppet.sh   [SWERVE_ARCH=amd64|arm64]
set -euo pipefail
HERE="$(cd "$(dirname "$0")" && pwd)"
ROOT="$(cd "$HERE/../../.." && pwd)"
ARCH="${SWERVE_ARCH:-amd64}"
RUST_TARGET="x86_64-unknown-linux-musl"; [ "$ARCH" = "arm64" ] && RUST_TARGET="aarch64-unknown-linux-musl"

echo "[puppet] cross-building moonshine ($RUST_TARGET) via zig …"
rustup target add "$RUST_TARGET" >/dev/null 2>&1 || true
( cd "$ROOT" && cargo zigbuild --release --target "$RUST_TARGET" --bin moonshine \
    --manifest-path open-source/gnosis/moonshine/Cargo.toml )
BIN="$HERE/target/$RUST_TARGET/release/moonshine"
[ -x "$BIN" ] || { echo "[puppet] FAILED: $BIN missing"; exit 1; }
strip "$BIN" 2>/dev/null || true
cp "$BIN" "$HERE/moonshine"
echo "[puppet] staged static moonshine: $(wc -c <"$HERE/moonshine") bytes"

# Resolve swerve (prefer the native release binary; the PATH wrapper may be unprovisioned).
if [ -x "$ROOT/open-source/swerve/target/release/swerve" ]; then SW="$ROOT/open-source/swerve/target/release/swerve";
elif command -v swerve >/dev/null 2>&1; then SW="swerve";
else echo "[puppet] swerve not found — build it: (cd open-source/swerve && cargo build --release --bin swerve)"; exit 1; fi

echo "[puppet] swerve-layering RUN-free image (linux/$ARCH) …"
( cd "$HERE" && SWERVE_ARCH="$ARCH" "$SW" build -f Containerfile.puppet-musl -t aeon-puppet:latest . )
echo "[puppet] image: aeon-puppet:latest (linux/$ARCH) — run: swerve cline aeon-puppet:latest -c \"The sovereign mesh is\""
